import type {FunctionComponent} from "react";
import type {IAutoCompleteElement, IDropdownSelect, IListBoxSelect, ICascadeSelect, IMultiSelect, ITreeSelect} from "@lmb-it/kitsconcerto-types";
import FormSelect from "./SelectContext";


export const KitsAutoComplete: FunctionComponent<IAutoCompleteElement> = props => {
    return <FormSelect shape={'autocomplete'} {...props} />
}

export const KitsDropdown: FunctionComponent<IDropdownSelect> = props => {
    return <FormSelect shape={'dropdown'} {...props} />
}


export const KitsMultiSelect: FunctionComponent<IMultiSelect> = props => {
    return <FormSelect shape={'multiselect'} {...props} />
}
export { KitsMultiSelect as MultiSelect };

export const KitsTreeSelect: FunctionComponent<ITreeSelect> = props => {
    return <FormSelect shape={'treeSelect'} {...props} />
}
export { KitsTreeSelect as TreeSelect };

export const KitsListBox: FunctionComponent<IListBoxSelect> = props => {
    return <FormSelect shape={'listBox'} {...props} />
}

export const KitsCascadeSelect: FunctionComponent<ICascadeSelect> = props => {
    return <FormSelect shape={'cascade'} {...props} />
}
